1	/**
2	 * https://docs.cloud.google.com/run/docs/authenticating/service-to-service
3	 */
4	const { GoogleAuth } = require("google-auth-library");
5	
6	const auth = new GoogleAuth();
7	
8	function isLocalHttpBackend(url) {
9	  try {
10	    const u = new URL(url);
11	    return (
12	      u.protocol === "http:" &&
13	      (u.hostname === "localhost" || u.hostname === "127.0.0.1")
14	    );
15	  } catch {
16	    return false;
17	  }
18	}
19	
20	/**
21	 * Cloud Run requires an OIDC identity token in Authorization.
22	 * The app JWT is forwarded in X-User-Authorization so backends can keep using req.headers.authorization.
23	 * Local HTTP backends skip OIDC; the browser's Authorization header is forwarded unchanged.
24	 */
25	async function attachInvokingIdentityHeaders(backendUrl, req) {
26	  if (isLocalHttpBackend(backendUrl)) {
27	    return;
28	  }
29	  const targetAudience = backendUrl.replace(/\/$/, "");
30	  const client = await auth.getIdTokenClient(targetAudience);
31	  const idToken = await client.idTokenProvider.fetchIdToken(targetAudience);
32	  const userAuth = req.headers.authorization;
33	  req.headers.authorization = `Bearer ${idToken}`;
34	  if (userAuth) {
35	    req.headers["x-user-authorization"] = userAuth;
36	  }
37	}
38	
39	module.exports = { attachInvokingIdentityHeaders };
