1	const express = require("express");
2	const httpProxy = require("http-proxy");
3	const { SERVICE_MAP } = require("../src/serviceMap");
4	const { attachInvokingIdentityHeaders } = require("../src/backendProxy");
5	const { apiKeyAuthMiddleware } = require("../src/apiKeyAuth");
6	
7	const router = express.Router();
8	
9	const proxy = httpProxy.createProxyServer({
10	  xfwd: true,
11	  proxyTimeout: 0,
12	  timeout: 0,
13	});
14	
15	proxy.on("error", (err, req, res) => {
16	  console.error("[BFF proxy error]", err?.message || err);
17	  if (res && !res.headersSent && typeof res.writeHead === "function") {
18	    res.writeHead(502, { "Content-Type": "application/json" });
19	    res.end(JSON.stringify({ error: "Bad gateway" }));
20	  }
21	});
22	
23	router.use(apiKeyAuthMiddleware);
24	
25	/**
26	 * /api/<service>/<backend-path>
27	 * Example: /api/core/getAllItems, /api/item_master/lib/getAllitems
28	 */
29	router.use(async (req, res) => {
30	  const pathname = req.path.replace(/^\//, "");
31	  const segments = pathname.split("/").filter(Boolean);
32	  const service = segments[0];
33	  const backendPath = segments.slice(1).join("/");
34	
35	  const backendUrl = SERVICE_MAP[service];
36	  if (!backendUrl) {
37	    return res.status(404).json({
38	      error: `Unknown backend service: ${service}`,
39	    });
40	  }
41	  if (!backendPath) {
42	    return res.status(404).json({ error: "Missing backend path" });
43	  }
44	
45	  const qIdx = req.url.indexOf("?");
46	  const search = qIdx !== -1 ? req.url.substring(qIdx) : "";
47	
48	  try {
49	    await attachInvokingIdentityHeaders(backendUrl, req);
50	    req.url = `/${backendPath}${search}`;
51	
52	    proxy.web(req, res, {
53	      target: backendUrl.replace(/\/$/, ""),
54	      changeOrigin: true,
55	    });
56	  } catch (err) {
57	    console.error(`[BFF ERROR] ${service} ${req.method} ${req.originalUrl}`, err.message);
58	    if (!res.headersSent) {
59	      res
60	        .status(err.response?.status || 500)
61	        .send(err.response?.data || { error: err.message || "Backend request failed" });
62	    }
63	  }
64	});
65	
66	module.exports = router;
