1	const crypto = require("crypto");
2	
3	const API_KEY_HEADER = "x-api-key";
4	const DEFAULT_JWT_TTL = "1h";
5	
6	function hashApiKey(apiKey) {
7	  return crypto.createHash("sha256").update(apiKey, "utf8").digest("hex");
8	}
9	
10	function safeEqual(a, b) {
11	  const left = Buffer.from(String(a || ""), "utf8");
12	  const right = Buffer.from(String(b || ""), "utf8");
13	  return left.length === right.length && crypto.timingSafeEqual(left, right);
14	}
15	
16	function parseDurationSeconds(value = DEFAULT_JWT_TTL) {
17	  const match = String(value).trim().match(/^(\d+)\s*(s|m|h|d)?$/i);
18	  if (!match) {
19	    throw new Error(`Invalid API_KEY_JWT_TTL: ${value}`);
20	  }
21	
22	  const amount = Number(match[1]);
23	  const unit = (match[2] || "s").toLowerCase();
24	  const multipliers = { s: 1, m: 60, h: 60 * 60, d: 24 * 60 * 60 };
25	  return amount * multipliers[unit];
26	}
27	
28	function base64url(input) {
29	  const buffer = Buffer.isBuffer(input) ? input : Buffer.from(JSON.stringify(input));
30	  return buffer
31	    .toString("base64")
32	    .replace(/=/g, "")
33	    .replace(/\+/g, "-")
34	    .replace(/\//g, "_");
35	}
36	
37	function parseApiKeys(raw = process.env.DESIGNFLOW_API_KEYS) {
38	  if (!raw || !raw.trim()) {
39	    return [];
40	  }
41	
42	  let parsed;
43	  try {
44	    parsed = JSON.parse(raw);
45	  } catch (err) {
46	    throw new Error("DESIGNFLOW_API_KEYS must be valid JSON");
47	  }
48	
49	  const entries = Array.isArray(parsed) ? parsed : [parsed];
50	  return entries.map((entry, index) => {
51	    const keyHash = entry.keyHash || (entry.key ? hashApiKey(entry.key) : null);
52	    const claims = entry.claims || {};
53	
54	    if (!keyHash) {
55	      throw new Error(`DESIGNFLOW_API_KEYS[${index}] is missing keyHash`);
56	    }
57	    if (!claims.user_id || !claims.email || !claims.role) {
58	      throw new Error(`DESIGNFLOW_API_KEYS[${index}] claims require user_id, email, and role`);
59	    }
60	
61	    return {
62	      name: entry.name || `api-key-${index + 1}`,
63	      keyHash,
64	      claims,
65	    };
66	  });
67	}
68	
69	function findApiKeyEntry(apiKey, entries = parseApiKeys()) {
70	  const incomingHash = hashApiKey(apiKey);
71	  return entries.find((entry) => safeEqual(incomingHash, entry.keyHash));
72	}
73	
74	function signInternalJwt(claims, options = {}) {
75	  const privateKey = options.privateKey || process.env.JWT_PRIVATE_KEY;
76	  if (!privateKey) {
77	    throw new Error("JWT_PRIVATE_KEY is required for API key authentication");
78	  }
79	
80	  const now = Math.floor(Date.now() / 1000);
81	  const ttlSeconds = parseDurationSeconds(options.ttl || process.env.API_KEY_JWT_TTL || DEFAULT_JWT_TTL);
82	  const header = { alg: "RS256", typ: "JWT" };
83	  const payload = {
84	    ...claims,
85	    iat: now,
86	    exp: now + ttlSeconds,
87	    auth_type: "api_key",
88	  };
89	
90	  const signingInput = `${base64url(header)}.${base64url(payload)}`;
91	  const signer = crypto.createSign("RSA-SHA256");
92	  signer.update(signingInput);
93	  signer.end();
94	  const signature = signer.sign(privateKey);
95	
96	  return `${signingInput}.${base64url(signature)}`;
97	}
98	
99	function apiKeyAuthMiddleware(req, res, next) {
100	  const apiKey = req.headers[API_KEY_HEADER];
101	  if (!apiKey) {
102	    return next();
103	  }
104	
105	  let entry;
106	  try {
107	    entry = findApiKeyEntry(apiKey);
108	  } catch (err) {
109	    console.error("[BFF API key config error]", err.message);
110	    return res.status(500).json({ error: "API key authentication is misconfigured" });
111	  }
112	
113	  if (!entry) {
114	    return res.status(401).json({ error: "Invalid API key" });
115	  }
116	
117	  try {
118	    req.headers.authorization = signInternalJwt({
119	      ...entry.claims,
120	      api_key_name: entry.name,
121	    });
122	    delete req.headers[API_KEY_HEADER];
123	    return next();
124	  } catch (err) {
125	    console.error("[BFF API key auth error]", err.message);
126	    return res.status(500).json({ error: "API key authentication failed" });
127	  }
128	}
129	
130	module.exports = {
131	  apiKeyAuthMiddleware,
132	  findApiKeyEntry,
133	  hashApiKey,
134	  parseApiKeys,
135	  signInternalJwt,
136	};
