1	const express = require("express");
2	const cors = require("cors");
3	const { env, envFile } = require("../config/env.js");
4	const { SERVICE_MAP } = require("./serviceMap.js");
5	const routes = require("../routes/index.js");
6	
7	const app = express();
8	
9	const corsOrigins = process.env.CORS_ORIGINS
10	  ? process.env.CORS_ORIGINS.split(/[|,]/).map((s) => s.trim()).filter(Boolean)
11	  : true;
12	
13	app.use(
14	  cors({
15	    origin: corsOrigins,
16	    credentials: true,
17	    allowedHeaders: [
18	      "Authorization",
19	      "Content-Type",
20	      "X-API-Key",
21	      "X-Enable-Loader",
22	      "Accept",
23	    ],
24	  })
25	);
26	
27	const port = process.env.PORT || 5004;
28	
29	// Fail fast if critical env vars are missing
30	Object.entries(SERVICE_MAP).forEach(([service, url]) => {
31	  if (!url) {
32	    console.warn(`[WARN] Backend URL not set for service: ${service}`);
33	  }
34	});
35	
36	app.use(routes);
37	
38	function startServer() {
39	  app.listen(port, "0.0.0.0", function () {
40	    console.log(`🚀 Server running on port ${port} in the ${env} environment`);
41	    console.log(`🧠 API Address: ${process.env.API_ADDRESS}`);
42	    console.log(`⚙️  Env File: ${envFile}`);
43	  });
44	}
45	
46	startServer();
